dataprocessscript.script:
import java.util.Base64

for (int i = 0; i < dataContext.getDataCount(); i++) {

    InputStream is = dataContext.getStream(i)
    Properties props = dataContext.getProperties(i)

    String xml = is.getText("UTF-8")

    // 🔥 Replace token-like strings safely
    xml = xml.replaceAll('[A-Za-z0-9+/=_-]{20,}', '\\$\\{MASKED\\}')

    // Encode
    String encoded = Base64.getEncoder().encodeToString(xml.getBytes("UTF-8"))

    InputStream newStream = new ${MASKED}(encoded.getBytes("UTF-8"))
    dataContext.storeStream(newStream, props)
}
